import React from "react";
import { Outlet, NavLink } from "react-router-dom";
import "./dashboard.css";

const DashboardLayout = () => {
  const user = localStorage.getItem("loggedInUser") || "User";

  return (
    <div className="dashboard-container">
      {/* LEFT SIDEBAR */}
      <div className="sidebar">
        <h2>📊 Dashboard</h2>
        <NavLink to="/dashboard" end>🏠 Home</NavLink>
        <NavLink to="/dashboard/profile">👤 Profile</NavLink>
        <NavLink to="/dashboard/products">📦 Products</NavLink>
        <NavLink to="/dashboard/settings">⚙️ Settings</NavLink>
      </div>

      {/* MAIN CONTENT */}
      <div className="content">
        <div className="welcome-center">
          <div className="welcome-card">
            <h1>Welcome, {user}! 👋</h1>
            <p>Glad to have you back. Here's what's happening with your business today.</p>
          </div>
        </div>
        <div className="page-container active">
          <h2>Vendor Panel</h2>
          <Outlet />
        </div>
      </div>
    </div>
  );
};

export default DashboardLayout;
